import{_ as n,c as o,o as t,ai as s}from"./chunks/framework.C8-0bFZC.js";const h=JSON.parse('{"title":"MCK Meeting Series","description":"","frontmatter":{"title":"MCK Meeting Series","date":"2026-01-20","banner":"assets/events/20262001_mck_neonephos_series_banner.svg","bannerMobile":"assets/events/20262001_mck_neonephos_series_banner_mobile.svg","bannerSmall":"assets/events/20262001_mck_neonephos_series_banner_small.svg","backgroundhex":"#128256ff","tags":["neonephos","mck","ipcei"],"published":true,"sidebar":false,"aside":false,"prev":false,"next":false,"layout":"EventEntryThemeComponent"},"headers":[],"relativePath":"events/2026_01_20_MCK_NeoNephos_Series.md","filePath":"events/2026_01_20_MCK_NeoNephos_Series.md"}'),r={name:"events/2026_01_20_MCK_NeoNephos_Series.md"};function a(i,e,l,c,p,d){return t(),o("div",null,e[0]||(e[0]=[s('<h1 id="neonephos-meeting-series" tabindex="-1">NeoNephos Meeting Series <a class="header-anchor" href="#neonephos-meeting-series" aria-label="Permalink to &quot;NeoNephos Meeting Series&quot;">​</a></h1><p>The next IPCEI-CIS Workstream 2 Multi Cluster Kubernetes (MCK) meeting session will be held on the <strong>20th of January from 10:00-11:30 am CET</strong>.</p><p>Agenda:</p><ul><li><strong>Efficient Microservices Delivery with Project Konfidence</strong> (40 min): Curious about how to best support the delivery of microservice-based SaaS applications across the cloud-edge continuum? Join us for an engaging session where we introduce Project Konfidence, a new open-source project aimed at transforming the delivery of microservice-based SaaS applications. Konfidence is designed to simplify and modernize the delivery of microservice-based SaaS applications, helping developers to focus on business logic rather than tool management. We’ll dive into how Konfidence fits into the Apeiro Reference Architecture (ApeiroRA), part of the Important Project of Common European Interest - Next Generation Cloud Infrastructures and Services (IPCEI-CIS). You&#39;ll learn how it streamlines software releases, reduces infrastructure complexity, and supports modern deployment strategies like ring deployments and feature toggle management, all while following CNCF best practices.</li><li><strong>Delivering and deploying OpenDesk with Open Component Model to AirGap</strong> (40 min): How do you package, transport, and deploy a complete digital workplace platform across disconnected or air-gapped Kubernetes environments in the cloud-edge continuum? In this talk, we demonstrate a component-based approach using Open Component Model (OCM) and OCM aware Kubernetes Deployer to deliver OpenDesk - a comprehensive sovereign workplace platform. Our solution addresses the full lifecycle: OCM enables technology-agnostic packaging of Helm charts, container images, configurations and many more into self-contained components stored in OCI registries. We showcase automated CI/CD workflows that package OCM components, transfer them to OCI registry ready for air-gapped environments, and deploy across Kubernetes clusters using OCM aware Kubernetes Deployer. This approach solves critical challenges in sovereign cloud scenarios where internet connectivity is restricted or regulated.</li></ul><hr><p>👉 Join the meeting <a href="https://teams.microsoft.com/l/meetup-join/19%3ameeting_NjgzOGUxNTItYjBjYy00NWZlLThkMjktNGZhMzM0NTg3MjZl%40thread.v2/0?context=%7b%22Tid%22%3a%2242f7676c-f455-423c-82f6-dc2d99791af7%22%2c%22Oid%22%3a%22f448159f-8442-4772-945c-ad5c1d621625%22%7d" target="_blank" rel="noreferrer">here</a>.</p>',6)]))}const g=n(r,[["render",a]]);export{h as __pageData,g as default};
